import{_ as a,o as r,c as t,a7 as i}from"./chunks/framework.C5fSpjcB.js";const m=JSON.parse('{"title":"Deckbuilding Guide","description":"","frontmatter":{},"headers":[],"relativePath":"en/cards/deckbuilding.md","filePath":"en/cards/deckbuilding.md","lastUpdated":1775394001000}'),s={name:"en/cards/deckbuilding.md"};function n(o,e,l,c,d,u){return r(),t("div",null,[...e[0]||(e[0]=[i('<h1 id="deckbuilding-guide" tabindex="-1">Deckbuilding Guide <a class="header-anchor" href="#deckbuilding-guide" aria-label="Permalink to &quot;Deckbuilding Guide&quot;">​</a></h1><p>Effective deckbuilding in Morimens means selecting the right Awakeners and understanding how their cards interact within a Designated Realm&#39;s mechanics.</p><h2 id="core-principles" tabindex="-1">Core Principles <a class="header-anchor" href="#core-principles" aria-label="Permalink to &quot;Core Principles&quot;">​</a></h2><ol><li><strong>Realm Cohesion</strong> -- Build your deck around one primary realm to maximize synergy.</li><li><strong>Arithmetica Curve</strong> -- Balance high-cost and low-cost cards so you can play efficiently each turn with your 5 Arithmetica budget.</li><li><strong>Win Condition</strong> -- Identify how your deck wins (burst damage, sustained pressure, Silver Key activation, etc.) and build toward it.</li><li><strong>Madness Management</strong> -- Factor in when Madness Burst will trigger and plan turns around the free ability.</li></ol><h2 id="deckbuilding-by-realm" tabindex="-1">Deckbuilding by Realm <a class="header-anchor" href="#deckbuilding-by-realm" aria-label="Permalink to &quot;Deckbuilding by Realm&quot;">​</a></h2><h3 id="chaos-decks" tabindex="-1"><span class="realm-badge realm-chaos">Chaos</span> Decks <a class="header-anchor" href="#chaos-decks" aria-label="Permalink to &quot;&lt;span class=&quot;realm-badge realm-chaos&quot;&gt;Chaos&lt;/span&gt; Decks&quot;">​</a></h3><p>Chaos decks are the most flexible, able to mix cards from multiple realms.</p><ul><li><strong>Silver Key Focus</strong> -- Chaos cards accelerate Silver Key generation. Build toward activating your <a href="./../key-orders/">Key Order</a> as the primary win condition.</li><li><strong>Hybrid Picks</strong> -- Include the strongest individual cards from other realms without worrying about breaking synergy.</li><li><strong>Versatility</strong> -- Best realm for players who lack a full roster in a single realm.</li></ul><div class="tip custom-block"><p class="custom-block-title">TIP</p><p>Chaos decks benefit from cards that generate Silver Key passively. Prioritize these over raw damage cards when building a Chaos-focused deck.</p></div><h3 id="aequor-decks" tabindex="-1"><span class="realm-badge realm-aequor">Aequor</span> Decks <a class="header-anchor" href="#aequor-decks" aria-label="Permalink to &quot;&lt;span class=&quot;realm-badge realm-aequor&quot;&gt;Aequor&lt;/span&gt; Decks&quot;">​</a></h3><p>Aequor decks revolve around summoning Tentacle entities and empowering them.</p><ul><li><strong>Summoning Engine</strong> -- Include enough Tentacle-summoning cards to maintain board presence.</li><li><strong>Tentacle Buffs</strong> -- Pair summoning cards with cards that enhance Tentacle damage or grant Tentacles additional effects.</li><li><strong>Sustained Damage</strong> -- Tentacles persist across turns, providing continuous damage while you play support cards.</li></ul><div class="tip custom-block"><p class="custom-block-title">TIP</p><p>A common mistake in Aequor deckbuilding is including too many summoning cards and not enough buff cards. Once you have 2-3 summoning sources, focus on empowerment.</p></div><h3 id="caro-decks" tabindex="-1"><span class="realm-badge realm-caro">Caro</span> Decks <a class="header-anchor" href="#caro-decks" aria-label="Permalink to &quot;&lt;span class=&quot;realm-badge realm-caro&quot;&gt;Caro&lt;/span&gt; Decks&quot;">​</a></h3><p>Caro decks create Embryo cards and consume them for powerful burst effects.</p><ul><li><strong>Generation and Consumption</strong> -- Balance cards that create Embryos with cards that consume them. Too many generators with no consumers leads to a clogged hand.</li><li><strong>Hand Management</strong> -- Embryo cards take up hand space. Plan your turn order carefully.</li><li><strong>Burst Windows</strong> -- Caro decks excel at burst damage when consuming multiple Embryos in a single turn.</li></ul><div class="warning custom-block"><p class="custom-block-title">WARNING</p><p>Embryo cards cost Arithmetica to play. Account for this additional cost when planning your Arithmetica curve.</p></div><h3 id="ultra-decks" tabindex="-1"><span class="realm-badge realm-ultra">Ultra</span> Decks <a class="header-anchor" href="#ultra-decks" aria-label="Permalink to &quot;&lt;span class=&quot;realm-badge realm-ultra&quot;&gt;Ultra&lt;/span&gt; Decks&quot;">​</a></h3><p>Ultra decks gain extra turns from playing multiple cards, creating snowball potential.</p><ul><li><strong>Low-Cost Cards</strong> -- Prioritize cards with low Arithmetica costs to play more cards per turn and trigger extra turn effects.</li><li><strong>Chain Potential</strong> -- Look for cards that draw additional cards or refund Arithmetica, extending your turn further.</li><li><strong>Momentum</strong> -- Ultra decks start slow but accelerate. Survive the early turns to reach your power spike.</li></ul><div class="tip custom-block"><p class="custom-block-title">TIP</p><p>Ultra decks live or die by Arithmetica efficiency. A single high-cost card can break your chain. Keep your average card cost as low as possible.</p></div><h2 id="general-deckbuilding-tips" tabindex="-1">General Deckbuilding Tips <a class="header-anchor" href="#general-deckbuilding-tips" aria-label="Permalink to &quot;General Deckbuilding Tips&quot;">​</a></h2><ul><li><strong>Upgrade key cards first</strong> -- A Lv 6 core card is worth more than several Lv 2 cards. See <a href="./upgrade.html">Card Upgrades</a>.</li><li><strong>Test in Investigation</strong> -- Use <a href="./../modes/investigation.html">Investigation</a> runs to experiment with card combinations before committing upgrade materials.</li><li><strong>Adapt to content</strong> -- Some stages favor certain realms or strategies. Do not be afraid to swap cards between runs.</li><li><strong>Consider Spirit Awakening timing</strong> -- Your Spirit Awakening Card is your strongest play. Build your deck to set up the conditions for maximum impact.</li></ul><h2 id="see-also" tabindex="-1">See Also <a class="header-anchor" href="#see-also" aria-label="Permalink to &quot;See Also&quot;">​</a></h2><ul><li><a href="./">Card System Overview</a></li><li><a href="./list.html">Card List</a></li><li><a href="./upgrade.html">Card Upgrades</a></li><li><a href="./../awakeners/team-building.html">Team Building</a></li><li><a href="./../realms/">Realms Overview</a></li></ul>',25)])])}const h=a(s,[["render",n]]);export{m as __pageData,h as default};
